function generateAccessToken(username) {
  return jwt.sign({ username }, ACCESS_TOKEN_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRATION });
}

function generateRefreshToken(username) {
  return jwt.sign({ username }, REFRESH_TOKEN_SECRET, { jwtid: uuidv4() });
}

async function storeRefreshToken(token, username) {
  await redisClient.setAsync(token, username, 'EX', REFRESH_TOKEN_EXPIRATION);
}

async function verifyAndFetchRefreshToken(token) {
  const username = await redisClient.getAsync(token);
  if (!username) return null;

  const payload = jwt.verify(token, REFRESH_TOKEN_SECRET);
  if (payload && payload.username === username) return username;
  
  return null;
}

